/** UsptStdrRsltIdxIemDetailDao.insert*/
insert into uspt_stdr_rslt_idx_detail_iem
							(
								rslt_idx_detail_iem_id
								, rslt_idx_id
								, detail_iem_nm
								, iem_unit_cd
								, creator_id
								, created_dt
								, updater_id
								, updated_dt
							)
					values	(
								#{rsltIdxDetailIemId}
								, #{rsltIdxId}
								, #{detailIemNm}
								, #{iemUnitCd}
								, #{creatorId}
								, #{createdDt}
								, #{updaterId}
								, #{updatedDt}
							)

mapper.update:
/** UsptStdrRsltIdxIemDetailDao.update */
update uspt_stdr_rslt_idx_detail_iem
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, detail_iem_nm	= #{detailIemNm}
	, iem_unit_cd	= #{iemUnitCd}
where
	rslt_idx_detail_iem_id = #{rsltIdxDetailIemId}
	and rslt_idx_id = #{rsltIdxId}

